USE exam_platform;

-- 408真题种子数据 v3: 846题 (18年 x 47题/年)
-- 题型分布: Q1-40选择题 + Q41-47大题
-- 科目分布: DS(1-11,41-42) CO(12-22,43-44) OS(23-32,45-46) CN(33-40,47)




































UPDATE chapter SET question_count = (SELECT COUNT(*) FROM question WHERE chapter_id = chapter.id AND status = 1);
SELECT 'Done: 846 real-style questions for 18 years' AS result;